export function setElemProps(e,t,o){for(const[o,n]of Object.entries(t))if("function"==typeof n&&o.startsWith("on")){const t=o.substring(2).toLowerCase();e.addEventListener(t,n,{passive:!1})}else if("object"==typeof n)for(const[t,r]of Object.entries(n))e[o][t]=r;else void 0===e[o]?e.setAttribute(o,n):e[o]=n;for(const t of o)e.appendChild(t);return e}export function createElem(e,t={},o=[]){const n=document.createElement(e);return setElemProps(n,t,o),n}export function addElem(e,t,o={},n=[]){const r=createElem(e,o,n);return t.appendChild(r),r}